import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as i,e as r}from"./app-be253e4c.js";const d={},h=r('<h1 id="备忘录模式" tabindex="-1"><a class="header-anchor" href="#备忘录模式" aria-hidden="true">#</a> 备忘录模式</h1><p>备忘录模式<code>Memento Pattern</code>是在不破坏封装性的前提下，将对象当前的内部状态保存在对象之外，以便以后当需要时能将该对象恢复到原先保存的状态。备忘录模式又叫快照模式，是一种对象行为型模式。</p><h2 id="基本介绍" tabindex="-1"><a class="header-anchor" href="#基本介绍" aria-hidden="true">#</a> 基本介绍</h2><p>备忘录模式是关于捕获和存储对象的当前状态的方式，以便以后可以平滑地恢复它。</p><h3 id="优点" tabindex="-1"><a class="header-anchor" href="#优点" aria-hidden="true">#</a> 优点</h3><ul><li>提供了一种可以恢复状态的机制，当用户需要时能够比较方便地将数据恢复到某个历史的状态。</li><li>实现了内部状态的封装，除了创建它的发起类之外，其他对象都不能够访问这些状态信息。</li><li>简化了发起类，发起类不需要管理和保存其内部状态的各个备份，所有状态信息都保存在备忘录中，并由管理者进行管理，这符合单一职责原则。</li></ul><h3 id="缺点" tabindex="-1"><a class="header-anchor" href="#缺点" aria-hidden="true">#</a> 缺点</h3><ul><li>资源消耗大，如果要保存的内部状态信息过多或者特别频繁，将会占用比较大的内存资源。</li></ul><h3 id="适用环境" tabindex="-1"><a class="header-anchor" href="#适用环境" aria-hidden="true">#</a> 适用环境</h3><ul><li>需要保存/恢复数据的相关状态场景。</li><li>提供一个可回滚的操作。</li></ul><h2 id="代码实现" tabindex="-1"><a class="header-anchor" href="#代码实现" aria-hidden="true">#</a> 代码实现</h2>',11),t=[h];function n(l,c){return a(),i("div",null,t)}const u=e(d,[["render",n],["__file","memento-mode.html.vue"]]);export{u as default};
